import type { Candidate, SearchFilters } from "@rearden/types";

export interface ScoredCandidate {
  candidate: Candidate;
  score: number;
  matchReason: string;
}

export function searchCandidates(
  candidates: Candidate[],
  query: string,
  filters?: SearchFilters
): ScoredCandidate[] {
  // Handle empty query - return all candidates with random scores
  if (!query.trim()) {
    return candidates
      .filter((candidate) => applyFilters(candidate, filters))
      .map((candidate) => ({
        candidate,
        score: Math.floor(Math.random() * 16) + 85, // 85-100
        matchReason: "Featured Talent",
      }))
      .sort((a, b) => b.score - a.score);
  }

  // Parse query into lowercase tokens
  const tokens = query.toLowerCase().trim().split(/\s+/);

  // Score each candidate
  const scoredCandidates = candidates
    .map((candidate): ScoredCandidate => {
      let totalScore = 0;
      const matchReasons: string[] = [];
      const matchedSkills: string[] = [];

      // Skill matching
      for (const skill of candidate.skills) {
        const skillLower = skill.toLowerCase();

        // Exact match
        if (tokens.some((token) => token === skillLower)) {
          totalScore += 25;
          matchedSkills.push(skill);
        }
        // Partial match
        else if (tokens.some((token) => skillLower.includes(token))) {
          totalScore += 15;
          matchedSkills.push(skill);
        }
      }

      if (matchedSkills.length > 0) {
        matchReasons.push(`Skills: ${matchedSkills.join(", ")}`);
      }

      // Title matching
      const titleLower = candidate.title.toLowerCase();
      const titleMatches = tokens.filter((token) => titleLower.includes(token));
      if (titleMatches.length > 0) {
        totalScore += titleMatches.length * 20;
        matchReasons.push(`Title: ${candidate.title}`);
      }

      // Location matching
      const locationLower = candidate.location.toLowerCase();
      const locationMatches = tokens.filter((token) => locationLower.includes(token));
      if (locationMatches.length > 0) {
        totalScore += locationMatches.length * 15;
        matchReasons.push(`Location: ${candidate.location}`);
      }

      // Bio matching
      const bioLower = candidate.bio.toLowerCase();
      const bioMatches = tokens.filter((token) => bioLower.includes(token));
      if (bioMatches.length > 0) {
        totalScore += bioMatches.length * 5;
      }

      // Experience keywords
      const queryLower = query.toLowerCase();
      if (queryLower.includes("senior") && candidate.experience >= 5) {
        totalScore += 10;
      }
      if (queryLower.includes("junior") && candidate.experience <= 3) {
        totalScore += 10;
      }
      if (queryLower.includes("lead") && candidate.experience >= 8) {
        totalScore += 10;
      }

      // Calculate max possible score for normalization
      const maxSkillScore = tokens.length * 25;
      const maxTitleScore = tokens.length * 20;
      const maxLocationScore = tokens.length * 15;
      const maxBioScore = tokens.length * 5;
      const maxExperienceBonus = 10;
      const maxPossibleScore =
        maxSkillScore + maxTitleScore + maxLocationScore + maxBioScore + maxExperienceBonus;

      // Normalize to 0-100
      const normalizedScore = maxPossibleScore > 0
        ? Math.min(100, Math.round((totalScore / maxPossibleScore) * 100))
        : 0;

      const matchReason = matchReasons.length > 0
        ? matchReasons.join(" | ")
        : "General match";

      return {
        candidate,
        score: normalizedScore,
        matchReason,
      };
    })
    .filter((scored) => scored.score > 0) // Filter out zero scores
    .filter((scored) => applyFilters(scored.candidate, filters)) // Apply additional filters
    .sort((a, b) => b.score - a.score); // Sort by score descending

  return scoredCandidates;
}

function applyFilters(candidate: Candidate, filters?: SearchFilters): boolean {
  if (!filters) return true;

  // Skills filter
  if (filters.skills && filters.skills.length > 0) {
    const candidateSkillsLower = candidate.skills.map((s) => s.toLowerCase());
    const hasAllSkills = filters.skills.every((skill) =>
      candidateSkillsLower.some((cs) => cs.includes(skill.toLowerCase()))
    );
    if (!hasAllSkills) return false;
  }

  // Location filter
  if (filters.location) {
    const locationMatch = candidate.location
      .toLowerCase()
      .includes(filters.location.toLowerCase());
    if (!locationMatch) return false;
  }

  // Experience range filter
  if (filters.experienceMin !== undefined && candidate.experience < filters.experienceMin) {
    return false;
  }
  if (filters.experienceMax !== undefined && candidate.experience > filters.experienceMax) {
    return false;
  }

  // Availability filter
  if (filters.availability && filters.availability.length > 0) {
    if (!filters.availability.includes(candidate.availability)) {
      return false;
    }
  }

  return true;
}

import { Hono } from "hono";
import type { ApiResponse, Candidate } from "@rearden/types";
import { mockCandidates } from "../data/mockCandidates.js";

export const candidateRoutes = new Hono();

// In-memory storage (starts with mock data)
let candidates: Candidate[] = [...mockCandidates];

// GET /api/candidates - Get all candidates
candidateRoutes.get("/", (c) => {
  return c.json<ApiResponse<Candidate[]>>({
    success: true,
    data: candidates,
  });
});

// GET /api/candidates/:id - Get candidate by ID
candidateRoutes.get("/:id", (c) => {
  const id = c.req.param("id");
  const candidate = candidates.find((cand) => cand.id === id);

  if (!candidate) {
    return c.json<ApiResponse>(
      {
        success: false,
        error: "Candidate not found",
      },
      404
    );
  }

  return c.json<ApiResponse<Candidate>>({
    success: true,
    data: candidate,
  });
});

// POST /api/candidates - Create new candidate
candidateRoutes.post("/", async (c) => {
  try {
    const body = await c.req.json();

    // Generate new candidate with ID and timestamps
    const now = new Date().toISOString();
    const newCandidate: Candidate = {
      id: crypto.randomUUID(),
      createdAt: now,
      updatedAt: now,
      role: "candidate" as const,
      resume: null,
      skills: [],
      experience: 0,
      videoUrl: null,
      thumbnailUrl: null,
      location: "",
      title: "",
      bio: "",
      availability: "immediate",
      ...body,
    };

    candidates.push(newCandidate);

    return c.json<ApiResponse<Candidate>>(
      {
        success: true,
        data: newCandidate,
      },
      201
    );
  } catch (error) {
    return c.json<ApiResponse>(
      {
        success: false,
        error: "Invalid request body",
      },
      400
    );
  }
});

import { Hono } from "hono";
import type { ApiResponse, SearchQuery, SearchResult } from "@rearden/types";
import { mockCandidates } from "../data/mockCandidates.js";
import { searchCandidates } from "../lib/searchEngine.js";

export const searchRoutes = new Hono();

// POST /api/search - Search candidates
searchRoutes.post("/", async (c) => {
  try {
    const body = (await c.req.json()) as SearchQuery;
    const { query, filters } = body;

    // Track search time
    const startTime = Date.now();

    // Artificial delay to simulate processing
    await new Promise((resolve) => setTimeout(resolve, 500));

    // Perform search
    const scoredCandidates = searchCandidates(mockCandidates, query, filters);

    const endTime = Date.now();
    const searchTimeMs = endTime - startTime;

    // Build response
    const results: (SearchResult & { candidate: typeof scoredCandidates[0]["candidate"] })[] =
      scoredCandidates.map((sc) => ({
        candidateId: sc.candidate.id,
        score: sc.score,
        matchReason: sc.matchReason,
        candidate: sc.candidate,
      }));

    return c.json<ApiResponse>({
      success: true,
      data: {
        results,
        query,
        totalCandidates: mockCandidates.length,
        searchTimeMs,
      },
    });
  } catch (error) {
    return c.json<ApiResponse>(
      {
        success: false,
        error: "Invalid search request",
      },
      400
    );
  }
});

import { Hono } from "hono";
import { existsSync, mkdirSync, writeFileSync, readFileSync } from "fs";
import { join, extname } from "path";
import type { ApiResponse } from "@rearden/types";

export const uploadRoutes = new Hono();

const UPLOAD_DIR = join(process.cwd(), "uploads");

// Ensure uploads directory exists
if (!existsSync(UPLOAD_DIR)) {
  mkdirSync(UPLOAD_DIR, { recursive: true });
}

// POST /api/upload - Upload file
uploadRoutes.post("/", async (c) => {
  try {
    const body = await c.req.parseBody();
    const file = body.file;

    if (!file || !(file instanceof File)) {
      return c.json<ApiResponse>(
        {
          success: false,
          error: "No file provided",
        },
        400
      );
    }

    // Generate unique filename
    const timestamp = Date.now();
    const ext = extname(file.name);
    const filename = `${timestamp}-${crypto.randomUUID()}${ext}`;
    const filepath = join(UPLOAD_DIR, filename);

    // Read file data and write to disk
    const arrayBuffer = await file.arrayBuffer();
    const buffer = Buffer.from(arrayBuffer);
    writeFileSync(filepath, buffer);

    return c.json<ApiResponse>({
      success: true,
      data: {
        url: `/api/upload/${filename}`,
        filename,
      },
    });
  } catch (error) {
    return c.json<ApiResponse>(
      {
        success: false,
        error: "Failed to upload file",
      },
      500
    );
  }
});

// GET /api/upload/:filename - Serve uploaded file
uploadRoutes.get("/:filename", (c) => {
  const filename = c.req.param("filename");
  const filepath = join(UPLOAD_DIR, filename);

  if (!existsSync(filepath)) {
    return c.json<ApiResponse>(
      {
        success: false,
        error: "File not found",
      },
      404
    );
  }

  try {
    const fileBuffer = readFileSync(filepath);
    const ext = extname(filename).toLowerCase();

    // Set appropriate content type
    const contentTypeMap: Record<string, string> = {
      ".pdf": "application/pdf",
      ".jpg": "image/jpeg",
      ".jpeg": "image/jpeg",
      ".png": "image/png",
      ".gif": "image/gif",
      ".webp": "image/webp",
      ".mp4": "video/mp4",
      ".webm": "video/webm",
      ".doc": "application/msword",
      ".docx": "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
      ".txt": "text/plain",
    };

    const contentType = contentTypeMap[ext] || "application/octet-stream";

    return c.body(fileBuffer, 200, {
      "Content-Type": contentType,
      "Content-Disposition": `inline; filename="${filename}"`,
    });
  } catch (error) {
    return c.json<ApiResponse>(
      {
        success: false,
        error: "Failed to read file",
      },
      500
    );
  }
});

